CREATE TABLE IF NOT EXISTS testimonials (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, role TEXT NOT NULL DEFAULT '', location TEXT NOT NULL DEFAULT '', quote TEXT NOT NULL, image_url TEXT NOT NULL DEFAULT '', display_order INT NOT NULL DEFAULT 0, is_featured BOOLEAN NOT NULL DEFAULT false, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());ALTER TABLE testimonials ENABLE ROW LEVEL SECURITY;CREATE POLICY testimonials_select_all ON testimonials FOR SELECT USING (true);CREATE POLICY testimonials_insert_service_role ON testimonials FOR INSERT WITH CHECK (auth.role() = 'service_role');CREATE POLICY testimonials_update_service_role ON testimonials FOR UPDATE USING (auth.role() = 'service_role');CREATE POLICY testimonials_delete_service_role ON testimonials FOR DELETE USING (auth.role() = 'service_role');